class Foo {
    fun good(list: List<Int>) {
        for (i in list) {
            if (i < 0) {
                continue
            }
            process(i)
        }
    }
    private fun process(i: Int) {}
}

class Foo {
    fun good(list: List<Int>) {
        for (i in list) {
            when (i) {
                0 -> break
            }
        }
    }
}

class Foo {
    fun good(items: List<String>) {
        for (item in items) {
            val fn = fun(): Boolean { return item.isNotEmpty() }
        }
    }
}

class Foo {
    fun good(items: List<String?>) {
        for (item in items) {
            val value = item ?: continue
            process(value)
        }
    }
    private fun process(s: String) {}
}

class Foo {
    fun good(items: Iterator<String?>) {
        while (items.hasNext()) {
            val value = items.next() ?: break
            process(value)
        }
    }
    private fun process(s: String) {}
}
